fn main() {
    let mut nums: Vec<i32> = vec![1, 2, 3];
    nums.push(4);
    println!("{:?}", nums);  // [1, 2, 3, 4]

    let last = nums.pop();  // Some(4)
    println!("{:?}", last);  // Some(4)
    println!("{}", nums.len());  // 3
    println!("{}", nums[0]);     // 1
}

