fn main() {
    let nums = vec![10, 20, 30, 40, 50];
    let slice = &nums[1..4];
    println!("{:?}", slice);  // [20, 30, 40]

    for x in &nums {
        print!("{} ", x);
    }
    println!();  // 10 20 30 40 50

    for (i, x) in nums.iter().enumerate() {
        print!("{}:{} ", i, x);
    }
    println!();  // 0:10 1:20 2:30 3:40 4:50
}

